import React from 'react';
import { Card, Col, Container, Row } from 'react-bootstrap';

const Research = () => {
  return (
      <>
        <Container className='p-3'>
          <h2> About Me </h2>

            <p>
              Continually trying to make my kids laugh, even when they tell me that I am not funny.
              My wife can attest to that, if you are looking for a reference.
              Always looking for the next new restaurant to add to my top list. 
            </p>

            <p>
              A forever student of science and engineering, with a continuing interest in understanding and analyzing complex problems. 
            </p>

            <p>
              Highly interested in  Machine Learning and Artificial Intelligence algorithms and applications of real world problems. 
            </p>


        </Container>
      </>

  );
};

export default Research;
